parsed.api_descriptions:
API_name: nchu_course_search_by_keyword
Description:
{
  "description": "依關鍵字搜尋中興大學課程資料庫中的課程。",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "搜尋關鍵字"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 10）",
      "default": 10
    },
    {
      "name": "search_fields",
      "type": "STRING",
      "description": "以逗號分隔的搜尋欄位（預設：科目名稱,上課教師,開課單位,系所名稱,備註）",
      "default": null
    },
    {
      "name": "case_sensitive",
      "type": "BOOLEAN",
      "description": "是否區分大小寫（預設為否）",
      "default": false
    },
    {
      "name": "include_syllabus_search",
      "type": "BOOLEAN",
      "description": "是否一併搜尋課程大綱內容（課程簡述、課程目標、每週授課內容等）（預設為否）",
      "default": false
    },
    {
      "name": "include_syllabus_in_result",
      "type": "BOOLEAN",
      "description": "是否在結果中包含完整大綱（預設為否）",
      "default": false
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼（例如「1142」代表 113-2）。若未指定，則使用最新學期。",
      "default": null
    }
  ]
}

